import "./CompanyDashboard.scss";

export default function CompanyDashboard() {

  const companyName =
    localStorage.getItem("username") || "Company";

  return (
    <div className="company-dashboard">
      <header className="company-header">
        <h1>🏢 {companyName}</h1>

        <button
          className="logout-btn"
          onClick={() => {
            localStorage.clear();
            window.location.href = "/";
          }}
        >
          Logout
        </button>
      </header>

      <div className="dashboard-cards">
        <div
          className="dashboard-card"
          onClick={() => (window.location.href = "/company/pending")}
        >
          <h2> New Bugs</h2>
          <p>Review & take action on submitted bugs</p>
        </div>

        <div
          className="dashboard-card"
          onClick={() => (window.location.href = "/company/history")}
        >
          <h2> Bug History</h2>
          <p>Approved, rejected & duplicate bugs</p>
        </div>
      </div>
    </div>
  );
}
